  ('social-worker-moex-01522', 'social-worker', 'social-worker-moex-108-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '有關Homans社會交換論的敘述，下列何者正確？', '["能夠獲得正向結果的行為，很可能會重複發生", "相似情境下的行為酬賞，極少在相似情境下再度出現", "行為結果出現與否和對該結果的正向酬賞，呈負相關", "人類行為模式並非以理性計算、獲得酬賞為目的"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:09+00:00", "source_pdf_sha1": "225c0ce9caca", "answer_pdf_sha1": "7f33815a6b91", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01523', 'social-worker', 'social-worker-moex-108-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '對於人類行為理論的敘述，下列何者正確？', '["系統觀點視人類行為是個體需求、欲求和情緒動機等內在動力的過程", "衝突觀點視人類行為來自內在理性自利，發揮內在向善力量的過程", "發展觀點視人類行為與生命週期有關，是具有規律性與變化性的過程", "社會建構觀點視人類行為是人際互動宰制、支配過程中所發展出來的結果"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:09+00:00", "source_pdf_sha1": "225c0ce9caca", "answer_pdf_sha1": "7f33815a6b91", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01524', 'social-worker', 'social-worker-moex-108-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '社會不單只是個人的加總，它還多出那些因為人及人心智反應物所產生的特性。以上敘述屬於系 統理論中的何種觀點？', '["整體論（holism）", "簡化論（reductionism）", "原子論（atomism）", "單一論（singulatism）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:09+00:00", "source_pdf_sha1": "225c0ce9caca", "answer_pdf_sha1": "7f33815a6b91", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01525', 'social-worker', 'social-worker-moex-108-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '關於「更年期」的敘述，下列何者錯誤？', '["大部分女性更年期出現在45至50歲", "男性更年期與女性更年期在差不多年紀出現", "男性更年期容易被忽視", "更年期是荷爾蒙分泌的改變"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:09+00:00", "source_pdf_sha1": "225c0ce9caca", "answer_pdf_sha1": "7f33815a6b91", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01526', 'social-worker', 'social-worker-moex-108-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '性騷擾問題在社會上越來越受關切。有關性騷擾的敘述，下列何者錯誤？', '["性騷擾幾乎與不平等權力有關", "低於20歲的女性遭到性騷擾的可能比20至40歲的女性要高出2倍", "性騷擾是發生在對異性的騷擾", "很多時候，揭發性騷擾事件的婦女被視為是麻煩製造者"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:09+00:00", "source_pdf_sha1": "225c0ce9caca", "answer_pdf_sha1": "7f33815a6b91", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01527', 'social-worker', 'social-worker-moex-108-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '相較於Piaget的認知發展理論，俄國心理學家Vygotsky提出兒童發展與學習的鷹架理論。下列 那一個敘述不屬於鷹架理論？', '["發展促成學習", "在同儕引導下學習，會造成發展的改變", "學習引導發展", "兒童最佳發展管道是需經由引導、啟發與教導才能達到較高層次的發展"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:09+00:00", "source_pdf_sha1": "225c0ce9caca", "answer_pdf_sha1": "7f33815a6b91", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01528', 'social-worker', 'social-worker-moex-108-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', 'Rutter（1984）指出具有某些特質的孩子能對壓力產生反擊。那些特質對反擊壓力是有幫助的？', '["兒童人格", "支持的家庭關係", "家庭經濟寬裕", "學習經驗"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:09+00:00", "source_pdf_sha1": "225c0ce9caca", "answer_pdf_sha1": "7f33815a6b91", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
