  ('social-worker-moex-01530', 'social-worker', 'social-worker-moex-108-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', 'Stroebe與Schut（1999）所謂哀悼因應的雙重過程模式的敘述包括：①哀悼有失落取向與恢復取', '["哀悼一定要先處理失落完成後，才能接下來處理恢復", "失落取向著重在哀傷情 緒的處理", "恢復取向著重在從哀悼中出來，進入新的角色與關係。下列何者正確？", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:09+00:00", "source_pdf_sha1": "225c0ce9caca", "answer_pdf_sha1": "7f33815a6b91", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 16, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
